}) {

    return (
        <Outer>
            <div
                style={{
                    display: 'flex',
                    flexDirection: 'column',
                    flexGrow: 1,
                    margin: '0 auto',
                    maxWidth: '80rem',                    
                }}
            >
                <div
                    style={{
                        flexGrow: 1,
                    }}
                >
                    {children}                    
                </div>
                <RelatedPages database={database} page={page} />
            </div>            
        </Outer>
    );
}

